use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    let modu: i64 = 1_000_000_007;
    let mut map = HashMap::new();
    for point in points {
        let y = point[1];
        *map.entry(y).or_insert(0) += 1;
    }

    let mut v = Vec::new();
    for count in map.values() {
        if *count >= 2 {
            let count = *count as i64;
            let comb = count * (count - 1) / 2;
            v.push(comb % modu);
        }
    }

    let mut total = 0;
    let mut s = 0;
    for val in v {
        total = (total + s * val) % modu;
        s = (s + val) % modu;
    }

    total
}
```

