    use std::collections::HashMap;

    let mut y_to_xs: HashMap<i64, Vec<i64>> = HashMap::new();
    for point in &points {
        let x = point[0];
        let y = point[1];
        y_to_xs.entry(y).or_default().push(x);
    }

    // Sort x-coordinates for each y-coordinate to facilitate counting
    for xs in y_to_xs.values_mut() {
        xs.sort_unstable();
    }

    let mut count = 0;
    let ys: Vec<_> = y_to_xs.keys().cloned().collect();
    let m = ys.len();

    for i in 0..m {
        let y1 = ys[i];
        let xs1 = &y_to_xs[&y1];
        let k1 = xs1.len();
        if k1 < 2 {
            continue;
        }

        for j in i + 1..m {
            let y2 = ys[j];
            let xs2 = &y_to_xs[&y2];
            let k2 = xs2.len();
            if k2 < 2 {
                continue;
            }

